/// <summary>
/// Headers and lines are creating from integration based on request.
/// </summary>
/// <param name = "Request"></param>
/// <returns></returns>
public ETGPurchAgreementAPIResponse create(ETGPurchAgreementAPIRequest _request)
{
    List lines;
    ListIterator   literator;
    ETGPurchAgreementLineAPIContract integrationRequestLine;
    int i;

    var response = new ETGPurchAgreementAPIResponse();
    {

        changecompany(_request.parmDataAreaId())
        {
            try
            {
                this.createHeader(_request.parmIntegrationHeaderClass());

                //Create lines
                lines = _request.parmIntegrationLineContractArray();
                if (lines)
                {
                    literator = new ListIterator(lines);
                    while (literator.more())
                    {
                        integrationRequestLine = literator.value();
                        this.createLine(_request.parmIntegrationHeaderClass(), integrationRequestLine);
                        literator.next();
                    }
                }

                //response.parmDebugMessage(_request.parmIntegrationHeaderClass());
                response.parmSuccess(true);
                Info(strFmt("%1 Response", response));
            }

            catch (Exception::CLRError)
            {
                System.Exception interopException = CLRInterop::getLastException();

                response.parmSuccess(false);
                response.parmErrorMessage(interopException.ToString());
                Info(strFmt("%1 Response", response));
            }
            return response;
        }
    }
}

/// <summary>
/// Headers data is creating from integration.
/// </summary>
/// <param name = "_requestHeader"></param>
public void createHeader(ETGPurchAgreementHeaderAPIContract _requestHeader)
{
    ETGPurchAgreementAPI header;
    ;

    ttsbegin;
    header.clear();
    header.VendAccount = _requestHeader.parmVendAccount();
    header.DealNumber = _requestHeader.parmDealNumber();
    header.EffectiveDate = _requestHeader.parmEffectiveDate();
    header.ExpirationDate = _requestHeader.parmExpirationDate();
    header.PaymentTerms = _requestHeader.parmPaymTerms();
    header.MethodOfPayment = _requestHeader.parmMethodOfPayment();
    header.DeliveryMode = _requestHeader.parmDeliveryMode();
    header.DeliveryTerm = _requestHeader.parmDeliveryTerms();
    header.Currency = _requestHeader.parmCurrencyCode();
    header.InvoiceAccount = _requestHeader.parmInvoiceAccount();
    header.PortOfLoading = _requestHeader.parmPlaceOfLoading();
    header.PortOfDischarge = _requestHeader.parmPlaceOfDischarge();
    header.BusinessUnit = _requestHeader.parmBusinessUnit();
    header.CostCenter = _requestHeader.parmCostCenter();        
    header.insert();
    ttscommit;


}

/// <summary>
/// Lines data is creating from integration
/// </summary>
/// <param name = "_requestHeader"></param>
/// <param name = "_requestLine"></param>
public void createLine(ETGPurchAgreementHeaderAPIContract _requestHeader, ETGPurchAgreementLineAPIContract _requestLine)
{
    ETGPurchAgreementLineAPI lines;
    ETGPurchAgreementAPI header;
    ;

    ttsbegin;       
    lines.clear();
    lines.ItemId = _requestLine.parmItemId();
    lines.Quantity = _requestLine.parmQuantity();
    lines.DealNumber = _requestLine.parmDealNumber();
    lines.Unit = _requestLine.parmUnit();
    lines.UnitPrice = _requestLine.parmUnitPrice();
    lines.InventSiteId = _requestLine.parmSite();
    lines.InventLocationId = _requestLine.parmWarehouse();
    lines.wMSLocationId = _requestLine.parmLocation();
    lines.configId = _requestLine.parmConfigId();
    lines.InventSizeId = _requestLine.parmSize();
    lines.InventColorId = _requestLine.parmColor();
    lines.InventStyleId = _requestLine.parmStyle();
    lines.ETG_UnderDeliveryPct = _requestLine.parmUnderDelivery();
    lines.ETG_OverDeliveryPct = _requestLine.parmOverDelivery();        
    lines.insert();
    ttscommit;
}
